import json, subprocess, sys
from datetime import datetime

def load_prompts(path="eval_prompts.json"):
    with open(path) as f:
        return json.load(f)

def run_ollama(prompt, model="llama3.2:3b"):
    try:
        r = subprocess.run(
            ["ollama", "run", model, prompt],
            capture_output=True, text=True, timeout=120
        )
        return r.stdout.strip()
    except Exception as e:
        return f"[error: {e}]"

def main():
    prompts = load_prompts()
    results = []
    for p in prompts:
        entry = {"id": p["id"], "category": p["category"],
                 "criteria": p["criteria"], "responses": {}}
        # Auto-run local model
        print(f"Running local model on: {p['id']}")
        entry["responses"]["llama3.2:3b"] = run_ollama(p["prompt"])
        # Placeholder for cloud models (manual paste)
        entry["responses"]["sonnet-5"] = "<paste from claude.ai>"
        entry["responses"]["gpt-free"] = "<paste from chatgpt.com>"
        results.append(entry)

    output = {"date": datetime.now().isoformat(), "results": results}
    with open("results.json", "w") as f:
        json.dump(output, f, indent=2)
    print(f"Saved {len(results)} results to results.json")
    print("Now paste cloud model responses into results.json")

if __name__ == "__main__":
    main()

